update public.activities as activity
set
  start_time = coalesce(updates.start_time, activity.start_time),
  end_time = coalesce(updates.end_time, activity.end_time),
  days_of_week = case when cardinality(updates.available_days_of_week) > 0 then updates.available_days_of_week else activity.days_of_week end,
  schedule_notes = coalesce(updates.schedule_notes, activity.schedule_notes),
  available_dates = updates.available_dates,
  availability_start_date = updates.availability_start_date,
  availability_end_date = updates.availability_end_date,
  available_days_of_week = updates.available_days_of_week,
  availability_type = updates.availability_type,
  availability_notes = updates.availability_notes,
  public_listing_status = 'published',
  updated_at = now()
from updates
where activity.activity_id = updates.activity_id;
